#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    int id;
    char name[25];
    int quantity;
} Product;

typedef struct {
    Product *arr;
    int size;
    int capacity;
} ProductList;

void initList(ProductList *list) {
    list->capacity = 4;
    list->size = 0;
    list->arr = malloc(list->capacity * sizeof(Product));
}

void addProduct(ProductList *list, int id, const char *name, int qty, int *posMap) {
    if (list->size == list->capacity) {
        list->capacity *= 2;
        list->arr = realloc(list->arr, list->capacity * sizeof(Product));
    }
    Product *p = &list->arr[list->size];
    p->id = id;
    strcpy(p->name, name);
    p->quantity = qty;
    posMap[id] = list->size; // store index (0‑based)
    list->size++;
}

void sellProduct(ProductList *list, int id, int qty, int *posMap) {
    int idx = posMap[id];
    if (idx >= 0 && idx < list->size) {
        Product *p = &list->arr[idx];
        if (p->quantity >= qty) p->quantity -= qty;
    }
}

void restockProduct(ProductList *list, int id, int qty, int *posMap) {
    int idx = posMap[id];
    if (idx >= 0 && idx < list->size) {
        list->arr[idx].quantity += qty;
    }
}

void displayProducts(ProductList *list) {
    for (int i = 0; i < list->size; ++i) {
        printf("ID: %d, Name: %s, Quantity: %d\n", list->arr[i].id, list->arr[i].name, list->arr[i].quantity);
    }
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; scanf("%d", &N);
        ProductList list; initList(&list);
        int posMap[1001];
        for (int i = 0; i <= 1000; ++i) posMap[i] = -1;
        for (int i = 0; i < N; ++i) {
            char op[10]; scanf("%s", op);
            if (strcmp(op, "add") == 0) {
                int id, qty; char name[25];
                scanf("%d %s %d", &id, name, &qty);
                addProduct(&list, id, name, qty, posMap);
            } else if (strcmp(op, "sell") == 0) {
                int id, qty; scanf("%d %d", &id, &qty);
                sellProduct(&list, id, qty, posMap);
            } else if (strcmp(op, "restock") == 0) {
                int id, qty; scanf("%d %d", &id, &qty);
                restockProduct(&list, id, qty, posMap);
            } else if (strcmp(op, "display") == 0) {
                displayProducts(&list);
            }
        }
        if (T) printf("\n"); // blank line between test cases
        free(list.arr);
    }
    return 0;
}

