#include <bits/stdc++.h>
using namespace std;

class Product {
public:
    int id;
    string name;
    int quantity;
    Product(int i, const string &n, int q) : id(i), name(n), quantity(q) {}
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int N; cin>>N;
        vector<Product> order; // preserves insertion order
        unordered_map<int,int> idx; // id -> position in order
        for (int i=0;i<N;++i) {
            string op; cin>>op;
            if (op=="add") {
                int id, qty; string name; cin>>id>>name>>qty;
                idx[id]=order.size();
                order.emplace_back(id,name,qty);
            } else if (op=="sell") {
                int id, qty; cin>>id>>qty;
                auto it=idx.find(id);
                if(it!=idx.end()) {
                    Product &p=order[it->second];
                    if(p.quantity>=qty) p.quantity-=qty;
                }
            } else if (op=="restock") {
                int id, qty; cin>>id>>qty;
                auto it=idx.find(id);
                if(it!=idx.end()) order[it->second].quantity+=qty;
            } else if (op=="display") {
                for(const auto &p:order) {
                    cout<<"ID: "<<p.id<<", Name: "<<p.name<<", Quantity: "<<p.quantity<<"\n";
                }
            }
        }
        if (T) cout<<"\n"; // blank line between test cases
    }
    return 0;
}

