import java.io.*;
import java.util.*;

class Product {
    int id;
    String name;
    int quantity;
    Product(int id, String name, int quantity) {
        this.id = id;
        this.name = name;
        this.quantity = quantity;
    }
}

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int tc = 0; tc < T; ++tc) {
            int N = Integer.parseInt(br.readLine().trim());
            List<Product> order = new ArrayList<>();
            Map<Integer, Integer> idx = new HashMap<>(); // id -> position in list
            for (int i = 0; i < N; ++i) {
                String line = br.readLine();
                StringTokenizer st = new StringTokenizer(line);
                String op = st.nextToken();
                if (op.equals("add")) {
                    int id = Integer.parseInt(st.nextToken());
                    String name = st.nextToken();
                    int qty = Integer.parseInt(st.nextToken());
                    idx.put(id, order.size());
                    order.add(new Product(id, name, qty));
                } else if (op.equals("sell")) {
                    int id = Integer.parseInt(st.nextToken());
                    int qty = Integer.parseInt(st.nextToken());
                    Integer pos = idx.get(id);
                    if (pos != null) {
                        Product p = order.get(pos);
                        if (p.quantity >= qty) p.quantity -= qty;
                    }
                } else if (op.equals("restock")) {
                    int id = Integer.parseInt(st.nextToken());
                    int qty = Integer.parseInt(st.nextToken());
                    Integer pos = idx.get(id);
                    if (pos != null) order.get(pos).quantity += qty;
                } else if (op.equals("display")) {
                    for (Product p : order) {
                        out.append("ID: ").append(p.id).append(", Name: ").append(p.name).append(", Quantity: ").append(p.quantity).append('\n');
                    }
                }
            }
            if (tc != T-1) out.append('\n'); // blank line between test cases
        }
        System.out.print(out.toString());
    }
}

