import sys

def main():
    data = sys.stdin.read().strip().split('\n')
    if not data:
        return
    t = int(data[0])
    line_idx = 1
    out_lines = []
    for _ in range(t):
        n = int(data[line_idx]); line_idx += 1
        products = []  # list preserving order
        pos = {}       # id -> index in products
        for _ in range(n):
            parts = data[line_idx].split(); line_idx += 1
            op = parts[0]
            if op == 'add':
                pid = int(parts[1]); name = parts[2]; qty = int(parts[3])
                pos[pid] = len(products)
                products.append([pid, name, qty])
            elif op == 'sell':
                pid = int(parts[1]); qty = int(parts[2])
                if pid in pos:
                    p = products[pos[pid]]
                    if p[2] >= qty:
                        p[2] -= qty
            elif op == 'restock':
                pid = int(parts[1]); qty = int(parts[2])
                if pid in pos:
                    products[pos[pid]][2] += qty
            elif op == 'display':
                for p in products:
                    out_lines.append(f"ID: {p[0]}, Name: {p[1]}, Quantity: {p[2]}")
        if _ != t-1:
            out_lines.append('')  # blank line between test cases
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

